const competitors = $input.all();
const config = $('Configuration').first().json;

const results = competitors
  .slice(0, config.competitor_count)
  .map((item, index) => ({
    json: {
      rank: index + 1,
      competitor_domain: item.json.domain,
      common_keywords: item.json.common_keywords || item.json.common || 0,
      your_domain: config.your_domain,
      source: config.source
    }
  }));

return results.length > 0 ? results : [{
  json: {
    rank: 1,
    competitor_domain: 'semrush.com',
    common_keywords: 0,
    your_domain: config.your_domain,
    source: config.source
  }
}];

const config = $('Configuration').first().json;
const allGaps = $input.all();
const currentCompetitor = $('Extract competitor domains').item.json;

const filtered = allGaps
  .filter(item => {
    const k = item.json;
    return k.volume >= config.min_volume && 
           k.difficulty <= config.max_difficulty;
  })
  .map(item => {
    const k = item.json;

    const volumeScore = k.volume * 0.4;
    const difficultyScore = (100 - k.difficulty) * 0.3;
    const trafficScore = (k.traffic || 0) * 0.3;
    const opportunityScore = Math.round(volumeScore + difficultyScore + trafficScore);

    return {
      json: {
        source: $('Wait before gap analysis').first().json.source,
        type: 'KEYWORD_GAP',
        competitor_domain: currentCompetitor.competitor_domain,
        keyword: k.keyword,
        volume: k.volume,
        difficulty: k.difficulty,
        cpc: k.cpc || 0,
        competition: k.competition || 0,
        competitor_position: k.position,
        estimated_traffic: k.traffic || Math.round(k.volume * 0.15),
        opportunity_score: opportunityScore,
        priority: opportunityScore > 5000 ? 'HIGH' : opportunityScore > 2000 ? 'MEDIUM' : 'LOW'
      }
    };
  });

return filtered;

const lostKeywords = $input.all();

const opportunities = lostKeywords
  .slice(0, 30)
  .map(item => {
    const k = item.json;
    const opportunityScore = Math.round((k.volume * 0.6) + ((100 - (k.difficulty || 50)) * 0.4));

    return {
      json: {
        type: 'LOST_KEYWORD',
        keyword: k.keyword,
        volume: k.volume,
        difficulty: k.difficulty || 50,
        cpc: k.cpc || 0,
        previous_position: k.prev_position || 'N/A',
        estimated_traffic_lost: Math.round(k.volume * 0.15),
        opportunity_score: opportunityScore,
        priority: 'HIGH',
        action: (k.difficulty || 50) < 40 ? 'QUICK WIN: Re-optimize' : 'Recover: Update content'
      }
    };
  });

return opportunities;

const similar = $('Get similar keywords').all();
const related = $('Get related keywords').all();
const config = $('Configuration').first().json;

// Extract keywords from nested structure
let allKeywords = [];

// Process similar keywords
similar.forEach(item => {
  if (item.json.keywords && Array.isArray(item.json.keywords)) {
    allKeywords = allKeywords.concat(item.json.keywords);
  }
});

// Process related keywords
related.forEach(item => {
  if (item.json.keywords && Array.isArray(item.json.keywords)) {
    allKeywords = allKeywords.concat(item.json.keywords);
  }
});

if (allKeywords.length === 0) {
  return [{
    json: {
      type: 'TOPIC_EXPANSION',
      keyword: 'NO_EXPANSION_DATA',
      volume: 0,
      difficulty: 0,
      cpc: 0,
      estimated_traffic: 0,
      opportunity_score: 0,
      priority: 'LOW',
      action: 'No expansion keywords found'
    }
  }];
}

const formatted = allKeywords
  .filter(k => k.volume >= config.min_volume)
  .map(k => {
    const opportunityScore = Math.round((k.volume * 0.5) + ((100 - (k.difficulty || 50)) * 0.5));

    return {
      json: {
        type: 'TOPIC_EXPANSION',
        keyword: k.keyword,
        volume: k.volume,
        difficulty: k.difficulty || 50,
        cpc: k.cpc || 0,
        estimated_traffic: Math.round(k.volume * 0.12),
        opportunity_score: opportunityScore,
        priority: opportunityScore > 3000 ? 'MEDIUM' : 'LOW',
        action: 'Expand: Add to content cluster'
      }
    };
  });

return formatted.length > 0 ? formatted : [{
  json: {
    type: 'TOPIC_EXPANSION',
    keyword: 'NO_KEYWORDS_PASSED_FILTERS',
    volume: 0,
    difficulty: 0,
    cpc: 0,
    estimated_traffic: 0,
    opportunity_score: 0,
    priority: 'LOW',
    action: 'No keywords passed volume filter'
  }
}];

const leaderboard = $input.first().json;
const config = $('Configuration').first().json;

// Extract YOUR domain's results from the actual API structure
const yourResults = leaderboard.results?.[config.your_domain] || {};

const aiMetrics = {
  your_domain: config.your_domain,
  your_brand: config.your_brand,
  chatgpt_presence: yourResults.chatgpt?.link_presence || 0,
  chatgpt_brand_presence: yourResults.chatgpt?.brand_presence || 0,
  perplexity_presence: yourResults.perplexity?.link_presence || 0,
  perplexity_brand_presence: yourResults.perplexity?.brand_presence || 0,
  gemini_presence: yourResults.gemini?.link_presence || 0,
  gemini_brand_presence: yourResults.gemini?.brand_presence || 0,
  ai_overview_presence: yourResults['ai-overview']?.link_presence || 0,
  ai_overview_brand_presence: yourResults['ai-overview']?.brand_presence || 0
};

return [{ json: aiMetrics }];

const allData = $input.all();

// Separate by actual data structure
const domainData = allData.filter(item => item.json.organic && item.json._domain);
const aiData = allData.filter(item => item.json.chatgpt_presence !== undefined);
const opportunities = allData.filter(item => item.json.keyword && item.json.type);

if (!domainData.length) throw new Error('No domain data - check connection');
if (!aiData.length) throw new Error('No AI data - check connection');

const config = $('Configuration').first().json;
const yourDomain = domainData[0].json;
const aiMetrics = aiData[0].json;

// Use actual structure: organic[0].keywords_count, traffic_sum, price_sum
const yourMetrics = {
  total_keywords: yourDomain.organic?.[0]?.keywords_count || 0,
  organic_traffic: yourDomain.organic?.[0]?.traffic_sum || 0,
  traffic_value: yourDomain.organic?.[0]?.price_sum || 0
};

const sorted = opportunities
  .map(item => item.json)
  .sort((a, b) => b.opportunity_score - a.opportunity_score);

return sorted.map((opp, index) => ({
  json: {
    rank: index + 1,
    analysis_date: new Date().toISOString().split('T')[0],
    your_domain: config.your_domain,
    your_brand: config.your_brand,
    your_total_keywords: yourMetrics.total_keywords,
    your_organic_traffic: yourMetrics.organic_traffic,
    your_traffic_value: yourMetrics.traffic_value,
    your_chatgpt_presence: aiMetrics.chatgpt_presence,
    your_chatgpt_brand_presence: aiMetrics.chatgpt_brand_presence,
    your_perplexity_presence: aiMetrics.perplexity_presence,
    your_perplexity_brand_presence: aiMetrics.perplexity_brand_presence,
    your_gemini_presence: aiMetrics.gemini_presence,
    your_gemini_brand_presence: aiMetrics.gemini_brand_presence,
    your_ai_overview_presence: aiMetrics.ai_overview_presence,
    your_ai_overview_brand_presence: aiMetrics.ai_overview_brand_presence,
    ...opp
  }
}));

// Extract top 10 keywords and output as individual items (one per keyword)
const allGaps = $('Filter & score keyword gaps').all();

if (allGaps.length === 0) {
  // No keywords found, return empty to skip topic expansion
  return [];
}

// Get top 10 keywords sorted by opportunity score
const topKeywords = allGaps
  .sort((a, b) => b.json.opportunity_score - a.json.opportunity_score)
  .slice(0, 10);

// Output each keyword as a separate item for the loop
return topKeywords.map(item => ({
  json: {
    source: $input.first().json.source,
    keyword: item.json.keyword
  }
}));
